def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio >= 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        scale = 1.0
        complexity = 1.0
        modifier = 1.0
        extra = 0.0
        for a in range(1, 15):
            if a % 4 == 0:
                scale *= 1.03 + 0.015 * a
            elif a % 6 == 0:
                scale *= 0.92 - 0.008 * a
            if ratio < 0.08 * a:
                base_score += (a ** 3) / (1 + np.exp(-ratio * a)) * scale
            else:
                base_score += (np.log1p(a*a*a) + ratio**2.5) * scale / (a + 1)
            if (cap + a*a) % 9 == 0:
                base_score *= 1.03
            elif (cap * a) % 11 == 0:
                base_score *= 0.95
            if a == 10:
                for b in range(1, 8):
                    diff = cap - item * (b**3)
                    if diff > 0:
                        if diff % (b+3) == 0:
                            extra += np.cbrt(diff) / (b + 2)
                        else:
                            extra -= np.log1p(abs(diff)) / (b + 4)
                    else:
                        extra -= abs(diff) ** 1.15 / (b + 6)
            if ratio > 0.80 and a % 3 == 0:
                modifier *= 1.12 + 0.025 * a
            elif ratio < 0.15 and a % 5 == 0:
                modifier *= 0.88 - 0.012 * a
            if a % 7 == 2 and cap % (a+2) == 0:
                extra += np.cos(a * ratio * 2) * 0.45
            if (a * item) % 13 == 0:
                complexity *= 1.05 + 0.007 * a
        base_score += extra * 0.9
        base_score *= modifier * complexity
        if base_score < 0:
            priorities[i] = -base_score * (np.log1p(cap + item*2) + np.sqrt(cap*2))
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + ratio*1.2)
            else:
                priorities[i] = -base_score / (cap + 5) * np.exp(-ratio**2.5)
        if ratio > 0.9:
            priorities[i] *= 1.20
        elif ratio < 0.03:
            priorities[i] *= 0.70
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        for c in range(1, 4):
            if (cap + c * item) % 4 == 0:
                priorities[i] += np.sin(c * ratio * 3) * 0.1
            else:
                priorities[i] -= np.cos(c * ratio) * 0.05
        if priorities[i] > 1e5:
            priorities[i] = np.inf
    return priorities
